var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤!","JPN":"アーシャ！","ENG":"Asha!","TWN":"阿莎！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"불순물 주제에…… 감히 우리의 은총을 뿌리쳐?","JPN":"不純物のくせに……私たちの恵みを拒否するのか？","ENG":"How dare an impurity... reject our grace?","TWN":"區區雜質……竟敢拒絕我們的恩惠？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤! 괜찮나요? 아샤!!","JPN":"アーシャ！　大丈夫ですか？　アーシャ！！","ENG":"Asha! Are you all right? ASHA!!","TWN":"阿莎！你沒事吧？阿莎！！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"정신이 들어요? 절 알아보겠어요?!","JPN":"気がつきましたか？　私のこと、わかりますか！？","ENG":"Are you all right? Can you recognize me?!","TWN":"你醒了嗎？還認得我嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"정말 제 이름을 알고 계셨네요…… 하하…….","JPN":"本当に私の名前を知ってたんですね……はは……","ENG":"You really did know my name... Haha...","TWN":"原來你真的知道我的名字……哈哈……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어떻게 된 거죠……? 저는 분명 그로니아에…….","JPN":"どういうことですか……？　私は確か、グロニアに……","ENG":"What happened...? I thought I was in Gronia...","TWN":"怎麼回事……？我明明在格羅尼亞……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"분명 라비의 모든 것을 흉내 냈습니다!","JPN":"確かにラビのすべてをコピーしたはずです！","ENG":"I have imitated everything about Ravi!","TWN":"我明明模仿了拉維的一切！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신의 과거를 추정하고, 당신이 지내던 어린 시절을 재구성했고, 당신이 보고 싶어하던 것들을 보여줬어요!","JPN":"あなたの過去を推定し、あなたが暮らしていた幼い頃を再構成し、あなたが見たいものをお見せしました！","ENG":"I even extrapolated your past, reconstructed your childhood, and even showed you what you wanted to see!","TWN":"我推測你的過去，重新建構你的童年，給你展示你想看到的東西！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 하찮을 정도로 이기적인 소원을 끝까지 들어주는 것조차 참아가면서 말입니다!","JPN":"そのくだらないほど自己中心的な願いを最後まで聞いてあげるほど我慢してまで！","ENG":"Even going as far as granting you your trivial wish!","TWN":"甚至還忍耐滿足你那微不足道的私慾！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"후우, 됐습니다. 애초에 우리가 뺏어버리면 될 일. 불순물은 신속히 흡수하면 됩니다.","JPN":"ふう、いいでしょう。そもそも私たちが奪ってしまえばいいこと。不純物は速やかに吸収すればいいのです。","ENG":"*Sigh* No matter. We can still take it away from you. All that is required is quickly absorbing the impurity.","TWN":"呼，原來如此。我們一開始就該直接搶過來。只要迅速吸收掉那個雜質就好。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그렇게 할 수는 없을 겁니다. 침식체.","JPN":"そうはいきません。侵食体。","ENG":"I won't let you do that, C.O.","TWN":"不會讓你得逞的，侵蝕體。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 얼굴, 아버지의 기억을 갖고 있다고 해서 당신이 라비가 될 수는 없어.","JPN":"お父さんの顔、お父さんの記憶を持っているからってあなたがラビになることなんてできないわ。","ENG":"Just because you have my father's memories and look like him, you can never become Ravi.","TWN":"即使擁有爸爸的樣貌和記憶，你也無法成為他。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"애초에 그 기억도 진짜가 아니잖아? 흩어진 것들을 모아다 기워 놨을 뿐이지.","JPN":"だいたい、その記憶だって本物じゃないんでしょ？　バラバラになったものを適当に寄せ集めただけじゃない。","ENG":"Those memories aren't real in the first place. All you have done is gathered bits and stitched them together.","TWN":"而且，那些記憶本來也不是真的吧？你只是把零散的東西拼湊起來而已。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 곧 라비입니다. 비록…….","JPN":"私がラビです。たとえ……","ENG":"I am Ravi. Even if...","TWN":"我很快就會變成拉維，雖然……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"당신은 그분의 기억과 육신을 흡수하지 못했어요.","JPN":"あなたはあの人の記憶と肉体を吸収できなかったのです。","ENG":"You have not absorbed his body and memories.","TWN":"你沒能吸收他的記憶和肉體。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그분이 받은 이름 그대로, 불꽃이 되어 모든 것을 불살랐으니까.","JPN":"あの人が受け継いだ名のとおり、炎になりすべてを燃やし尽くしましたから。","ENG":"Because he became a flame and burned everything, just like the name he was given.","TWN":"就像他得到的名字一樣，他化作一束焚盡一切的火焰。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그렇기에 아샤의 존재에 대해 깊은 관심을 가지지 않은 건 당연한 일.","JPN":"ですから、アーシャについて深く知ろうとしなかったのは当然のこと。","ENG":"Thus, it's natural that you had no interest in Asha's existence.","TWN":"而你自然也不會對阿莎的存在有過多關注。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"대충 기워 만든 육신과 기억으로는 아샤를 현혹할 수 없었을 겁니다.","JPN":"中途半端に繋げた肉体と記憶だけではアーシャを惑わすことはできなかったはずです。","ENG":"You cannot deceive Asha with that crudely made body and memories.","TWN":"憑藉粗製濫造的身體和記憶，是無法蠱惑阿莎的！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아직…… 아직 기회는 충분합니다. ","JPN":"まだ……まだ十分チャンスはあります。 ","ENG":"Yet... there are still plenty of opportunities left.","TWN":"還……還有機會。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신들은 이곳을 나갈 수 없을 테니까!","JPN":"あなたたちはここから出られないはずですから！","ENG":"For you all cannot escape this place!","TWN":"你們是無法離開這裡的！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저는 반드시 끝마쳐야 하는 임무가 있어요.","JPN":"私には必ず最後まで成し遂げないといけない任務があります。","ENG":"There is a mission I must complete.","TWN":"我有一個必須完成的任務。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"무슨 수를 써서라도 그 일을 완수해야 합니다.","JPN":"どんな手を使ってでもその任務を完遂しないと。","ENG":"Whatever the cost, I must get it done.","TWN":"不管用什麼辦法，都必須完成那件事。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"악을 정화하기 위해서, 모든 것을 잃더라도 저는 나아가야 해요.","JPN":"悪を浄化するために、すべてを失うことになっても私は進まなければなりません。","ENG":"To purify the evil, I must move on even if it means losing everything.","TWN":"為了淨化邪惡，即使失去一切，我也要前進。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};